"""This scripts generates JSON files that contain information about
the stages that are available in PSANP. Those files can then be
uploaded to S3 and be used by the PSANP SaaS app
"""

import inspect
import json
import logging
import os
from argparse import ArgumentParser, ArgumentDefaultsHelpFormatter
from pathlib import Path
from typing import List, Any, Dict, Set, Type

from geosat.psanp.abstractions.classifier import Classifier
from geosat.psanp.abstractions.stage import Stage
from geosat.psanp.abstractions.stages import (
    REGISTERED_STAGES,
    register_plugin_stages,
    get_stage,
)
from geosat.tools.urlprotocol import UrlProtocols, UrlWriter

from psanp.standard_stages import register_standard_stages


def gather_stages(stages: Dict[str, Stage]) -> List[Dict[str, Any]]:
    all_stages: List[Dict[str, Any]] = []
    for stage_name, stage in stages.items():
        options_dicts: List[Dict[str, Any]] = []
        for option in stage.options():
            d = dict(option.to_dict())
            if not option.required:
                d["default"] = str(getattr(stage, option.name))
            options_dicts.append(d)
        all_stages.append(
            {
                "name": stage_name,
                "description": (
                    inspect.cleandoc(stage.__doc__)
                    if stage.__doc__ is not None
                    else None
                ),
                "options": options_dicts,
            }
        )
    return all_stages


def gather_classifiers(stages: Dict[str, Stage]) -> List[Dict[str, Any]]:
    all_classifiers: List[Dict[str, Any]] = []
    for stage_name, stage in stages.items():
        if isinstance(stage, Classifier):
            all_classifiers.append(
                {
                    "name": stage_name,
                    "input_classes": list(stage.input_classes()),
                    "output_classes": list(stage.output_classes()),
                }
            )
    return all_classifiers


def write_json_file(output_directory: str, filename: str, json_object: Any) -> None:
    protocols = UrlProtocols()
    output_url = protocols.integrate_path(
        output_directory, Path(protocols.extract_path(output_directory), filename)
    )
    with UrlWriter(output_url, protocols, use_strings=True) as f:
        json.dump(json_object, f, indent=2)


def query_bundle_stems() -> Set[str]:
    urlp = UrlProtocols()
    bundle_names: Set[str] = set()
    for url in urlp.list(os.environ["PSANP_BUNDLE_FOLDER"]):
        path = urlp.extract_path(url)
        if path.suffix == ".zip":
            bundle_names.add(path.stem)
    return bundle_names


def main() -> None:
    logging.basicConfig(level=logging.INFO)
    parser = ArgumentParser(
        "Generate two .json files that reference the different stages and classifiers",
        formatter_class=ArgumentDefaultsHelpFormatter,
    )
    parser.add_argument(
        "-o",
        "--output_directory",
        help="Url to the directory where to store the files",
        default=".",
    )
    args = parser.parse_args()
    register_standard_stages()
    register_plugin_stages()
    stage_names: Set[str] = set(REGISTERED_STAGES.keys())
    stage_names.update(query_bundle_stems())
    stages: Dict[str, Stage] = {}
    for stage_name in stage_names:
        logging.info(f"Loading Stage {stage_name}")
        stage_cls: Type[Stage] = get_stage(stage_name)
        try:
            stage = stage_cls(stage_name=stage_name)
        except FileNotFoundError as exception:
            # Bundle not found for base Classifiers like SusannV2Classifier, PointNetClassifier...
            logging.warning(f"Failed to instantiate Stage {stage_name}: {exception}")
            continue
        stages[stage_name] = stage
    write_json_file(args.output_directory, "../stages.json", gather_stages(stages))
    write_json_file(
        args.output_directory, "../classifiers.json", gather_classifiers(stages)
    )


if __name__ == "__main__":
    main()
